#include <stdio.h>
int main() {
    int num = 42;
    float pi = 3.14159;

    // Field width examples
    printf("|%d|\n", num);       // 42
    printf("|%5d|\n", num);      // |   42| (width 5, right-aligned)
    printf("|%-5d|\n", num);     // |42   | (left-aligned)

    // Precision examples
    printf("|%f|\n", pi);        // 3.141590
    printf("|%.2f|\n", pi);      // 3.14
    printf("|%.4f|\n", pi);      // 3.1416

    // Combined width and precision
    printf("|%10.2f|\n", pi);    // |      3.14| (width 10, 2 decimals)

    return 0;
}

#include <stdio.h>

int main() {
    float temp, result;
    int choice;

    printf("=== Temperature Converter ===\n\n");
    printf("1. Celsius to Fahrenheit\n");
    printf("2. Fahrenheit to Celsius\n");
    printf("Enter your choice (1 or 2): ");
    scanf("%d", &choice);

    if (choice == 1) {
        printf("\nEnter temperature in Celsius: ");
        scanf("%f", &temp);
        result = (temp * 9.0 / 5.0) + 32;
        printf("\n%.2f°C = %.2f°F\n", temp, result);
    } else if (choice == 2) {
        printf("\nEnter temperature in Fahrenheit: ");
        scanf("%f", &temp);
        result = (temp - 32) * 5.0 / 9.0;
        printf("\n%.2f°F = %.2f°C\n", temp, result);
    } else {
        printf("\nInvalid choice!\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    // Using getchar() and putchar()
    char ch;
    printf("Enter a character: ");
    ch = getchar();
    printf("You entered: ");
    putchar(ch);
    putchar('\n');

    // Using gets() and puts() (note: gets() is unsafe)
    char name[30];
    printf("\nEnter your name: ");
    // Use fgets() instead of gets() for safety
    fgets(name, 30, stdin);
    // Remove newline if present
    name[strcspn(name, "\n")] = 0;

    printf("Hello, ");
    puts(name);

    return 0;
}
